    clusterManager.join(joinPromise);
    return initPromise
      .future()
      .transform(ar -> {
        if (ar.succeeded()) {
          if (metrics != null) {
            metrics.vertxCreated(this);
          }
          return Future.succeededFuture(this);
        } else {
